// Robustes JSON-Parsing: extrahiert erstes {...}-Objekt aus dem QA-Output.
// Fallback bei Parse-Error -> Original-Output im Kunden-Draft.
const raw = ($input.item.json.output || $input.item.json.result || '').toString();
const match = raw.match(/\{[\s\S]*\}/);
let parsed;
try {
  parsed = JSON.parse(match ? match[0] : raw);
} catch (e) {
  parsed = {
    klassifikation:     { sparte: 'unbekannt', schadenart: 'parse-error', dringlichkeit: 'sofort' },
    sofort_massnahmen:  ['QA-Output konnte nicht geparst werden — bitte manuell pruefen'],
    mail_an_kunden:     raw,
    mail_an_versicherer: raw,
    _parse_error:       e.message,
  };
}
return { json: { ...$input.item.json, parsed } };

